TMPDIR=$(mktemp -d)

# Functions with enough nodes (min_nodes=20) for equal-score pairs
cat > "$TMPDIR/aaa.rs" << 'EOF'
fn alpha() {
    let a = 1;
    let b = 2;
    let c = a + b;
    let d = c * 3;
    let e = d - 1;
    let f = e / 2;
    let g = f + a;
    let h = g * b;
    println!("{} {} {} {} {} {}", c, d, e, f, g, h);
}
fn beta() {
    let a = 1;
    let b = 2;
    let c = a + b;
    let d = c * 3;
    let e = d - 1;
    let f = e / 2;
    let g = f + a;
    let h = g * b;
    println!("{} {} {} {} {} {}", c, d, e, f, g, h);
}
EOF

cat > "$TMPDIR/bbb.rs" << 'EOF'
fn gamma() {
    let a = 1;
    let b = 2;
    let c = a + b;
    let d = c * 3;
    let e = d - 1;
    let f = e / 2;
    let g = f + a;
    let h = g * b;
    println!("{} {} {} {} {} {}", c, d, e, f, g, h);
}
fn delta() {
    let a = 1;
    let b = 2;
    let c = a + b;
    let d = c * 3;
    let e = d - 1;
    let f = e / 2;
    let g = f + a;
    let h = g * b;
    println!("{} {} {} {} {} {}", c, d, e, f, g, h);
}
EOF

COUNT=$(./target/release/drywall "$TMPDIR" --format json 2>/dev/null | python3 -c "import sys,json; d=json.load(sys.stdin); print(len(d))")
echo "Pair count: $COUNT"

