fn order_endpoints<'a>(
    a: &'a FunctionInfo,
    b: &'a FunctionInfo,
) -> (&'a FunctionInfo, &'a FunctionInfo) {
    let cmp = a
        .file
        .cmp(&b.file)
        .then_with(|| a.start_line.cmp(&b.start_line));
    if cmp == std::cmp::Ordering::Greater {
        (b, a)
    } else {
        (a, b)
    }
